#include <iostream>
#include <map>
#include <string>
using namespace std;

int main() {
    map<string, int> scores;
    scores["Alice"] = 88;
    scores["Bob"]   = 72;
    scores["Carol"] = 95;
    scores["David"] = 80;

    // Access:
    cout << scores["Carol"] << endl;
    cout << scores.at("Bob") << endl;

    // Iterate (sorted by key!):
    for (const auto& [name, score] : scores) {
        cout << name << ": " << score << endl;
    }

    // Check if key exists:
    cout << boolalpha << (scores.count("Eve") > 0) << endl;

    return 0;
}

#include <iostream>
#include <unordered_map>
#include <string>
using namespace std;

int main() {
    unordered_map<string, int> wordCount;
    string words[] = {"the", "quick", "brown", "fox", "the", "fox", "the"};

    for (const auto& word : words) {
        wordCount[word]++;  // creates with 0 if not exists, then increments
    }

    for (const auto& [word, count] : wordCount) {
        cout << word << ": " << count << endl;
    }

    cout << "'the' appears: " << wordCount["the"] << " times" << endl;

    return 0;
}

#include <iostream>
#include <set>
#include <unordered_set>
#include <vector>
using namespace std;

int main() {
    // set — unique, sorted:
    set<int> nums = {5, 2, 8, 1, 5, 9, 3, 2};
    for (int n : nums) cout << n << " ";  // sorted, no duplicates
    cout << endl;

    // Membership test:
    cout << boolalpha << (nums.count(5) > 0) << endl;
    cout << (nums.count(7) > 0) << endl;

    // Deduplicate a vector:
    vector<string> langs = {"C++", "Python", "C++", "Java", "Python"};
    set<string> unique(langs.begin(), langs.end());
    for (const auto& l : unique) cout << l << " ";
    cout << endl;

    return 0;
}

#include <iostream>
#include <stack>
#include <queue>
#include <priority_queue>
using namespace std;

int main() {
    // Stack:
    stack<int> st;
    st.push(1); st.push(2); st.push(3);
    while (!st.empty()) { cout << st.top() << " "; st.pop(); }
    cout << endl;

    // Queue:
    queue<string> q;
    q.push("Alice"); q.push("Bob"); q.push("Carol");
    while (!q.empty()) { cout << q.front() << " "; q.pop(); }
    cout << endl;

    // Priority queue (max-heap by default):
    priority_queue<int> pq;
    pq.push(5); pq.push(2); pq.push(8); pq.push(1); pq.push(9);
    while (!pq.empty()) { cout << pq.top() << " "; pq.pop(); }
    cout << endl;

    return 0;
}

#include <iostream>
#include <map>
#include <vector>
#include <string>
using namespace std;

int main() {
    // pair:
    pair<string, int> p1 = {"Alice", 90};
    auto p2 = make_pair("Bob", 85);
    cout << p1.first << ": " << p1.second << endl;
    cout << p2.first << ": " << p2.second << endl;

    // map uses pairs internally:
    map<string, int> scores;
    scores.insert({"Carol", 95});
    scores.insert(make_pair("David", 78));

    for (auto& [name, score] : scores)
        cout << name << ": " << score << endl;

    // Sort vector of pairs by second element:
    vector<pair<string, int>> v = {{"C",3},{"A",1},{"B",2}};
    sort(v.begin(), v.end(),
         [](const auto& x, const auto& y){ return x.second < y.second; });
    for (auto& [c, n] : v) cout << c << ":" << n << " ";
    cout << endl;

    return 0;
}
